(function(){
const $=(s,r=document)=>r.querySelector(s),$$=(s,r=document)=>[...r.querySelectorAll(s)];
function msg(text,type='info'){const e=$('#auth-message');if(!e)return;e.textContent=text;e.className='auth-message '+type;e.hidden=false}
async function refresh(){const user=await DLBackend.user();$$('[data-auth-only]').forEach(x=>x.hidden=!user);$$('[data-guest-only]').forEach(x=>x.hidden=!!user);$$('[data-user-email]').forEach(x=>x.textContent=user?.email||'');if(user&&$('#account-email'))$('#account-email').textContent=user.email;if(user&&$('#account-id'))$('#account-id').textContent=user.id;if(!DLBackend.configured)msg('Supabase is not configured yet. Forms use local demo storage until config.js is completed.','warning')}
$('#signup-form')?.addEventListener('submit',async e=>{e.preventDefault();const f=new FormData(e.currentTarget);try{const {data,error}=await DLBackend.signUp(f.get('email'),f.get('password'),{display_name:f.get('name'),role:f.get('role')});if(error)throw error;msg(data.session?'Account created.':'Account created. Check your email to confirm the address.','success');if(data.session)setTimeout(()=>location.href='/onboarding',700)}catch(err){msg(err.message,'error')}});
$('#login-form')?.addEventListener('submit',async e=>{e.preventDefault();const f=new FormData(e.currentTarget);try{const {data,error}=await DLBackend.signIn(f.get('email'),f.get('password'));if(error)throw error;msg('Signed in.','success');setTimeout(()=>location.href='/mission-control',500)}catch(err){msg(err.message,'error')}});
$('#reset-form')?.addEventListener('submit',async e=>{e.preventDefault();try{await DLBackend.reset(new FormData(e.currentTarget).get('email'));msg('Password reset email requested.','success')}catch(err){msg(err.message,'error')}});
$$('[data-signout]').forEach(b=>b.addEventListener('click',async()=>{await DLBackend.signOut();location.href='/account'}));
$('#onboarding-form')?.addEventListener('submit',async e=>{e.preventDefault();const user=await DLBackend.user();const f=new FormData(e.currentTarget);const role=f.get('role');const profile={id:user?.id||crypto.randomUUID(),role,display_name:f.get('name'),company_name:f.get('company')||null};try{await DLBackend.upsert('profiles',profile,'id');if(role==='driver')await DLBackend.upsert('driver_passports',{user_id:profile.id,cdl_class:f.get('cdl_class'),availability:f.get('availability'),profile_visibility:'private'},'user_id');localStorage.setItem('dl-role',role);msg('Profile saved.','success');setTimeout(()=>location.href=role==='driver'?'/mission-control':'/portal',600)}catch(err){msg(err.message,'error')}});
refresh();
})();